// Leer el carrito desde SESSION
const sessionData = $('Leer estado Usuario').item.json;
let carritoData;

try {
  carritoData = JSON.parse(sessionData.carrito_temporal);
} catch(e) {
  return [{
    json: {
      valido: false,
      mensaje: "⚠️ Error al leer el carrito. Escribe /start para reiniciar."
    }
  }];
}

const items = carritoData.items || [];
const total = carritoData.total || 0;

if (items.length === 0) {
  return [{
    json: {
      valido: false,
      mensaje: "⚠️ Tu carrito está vacío. Escribe /start para reiniciar."
    }
  }];
}

// Leer todos los productos del MENU con su stock actual
const menuRows = $input.all();

// Validar stock para cada item del carrito
const erroresStock = [];
const actualizacionesStock = [];

for (const item of items) {
  const productoEnMenu = menuRows.find(row => row.json.id_producto === item.id);

  if (!productoEnMenu) {
    erroresStock.push(`❌ Producto ${item.nombre} ya no está disponible.`);
    continue;
  }

  const stockActual = Number(productoEnMenu.json.stock);

  if (stockActual < item.cantidad) {
    erroresStock.push(`❌ *${item.nombre}*: solo quedan ${stockActual} unidades (pediste ${item.cantidad}).`);
  } else {
    actualizacionesStock.push({
      id_producto: item.id,
      stock_nuevo: stockActual - item.cantidad,
      row_number: productoEnMenu.json.row_number
    });
  }
}

// Si hay errores de stock, detener
if (erroresStock.length > 0) {
  return [{
    json: {
      valido: false,
      mensaje: `⚠️ *Stock insuficiente:*\n\n${erroresStock.join('\n')}\n\nModifica tu carrito o escribe /start para reiniciar.`
    }
  }];
}

// Todo OK — generar pedido
const timestamp = Date.now();
const chatId = $('Ajuste Variables').item.json.chat_id;
const idPedido = `PED-${chatId}-${timestamp}`;

const ahora = new Date();
const fecha = ahora.toISOString().split('T')[0];
const hora = ahora.toTimeString().split(' ')[0];

const detalle = items.map(i => `${i.nombre} x${i.cantidad}`).join(' | ');

return [{
  json: {
    valido: true,
    id_pedido: idPedido,
    id_usuario: chatId,
    detalles_pedido: detalle,
    total_pago: total,
    estado: 'Recibido',
    fecha: fecha,
    hora: hora,
    items: items,
    actualizaciones_stock: actualizacionesStock,
    mensaje_cliente: `✅ *¡Pedido confirmado!*\n\n📋 *N° ${idPedido}*\n\n${items.map(i => `• ${i.nombre} x${i.cantidad} = $${i.subtotal}`).join('\n')}\n\n💰 *Total: $${total}*\n\n⏳ Tu pedido está siendo preparado. Te notificaremos cuando esté listo.`,
    mensaje_cocina: `🔔 *Nuevo pedido*\n\n📋 N° ${idPedido}\n👤 Cliente: ${chatId}\n\n${items.map(i => `• ${i.nombre} x${i.cantidad}`).join('\n')}\n\n💰 Total: $${total}`
  }
}];

const numeroEscrito = String($('Ajuste Variables').item.json.texto_usuario).trim();

const sessionData = $input.first().json;
const mapaRaw = sessionData.carrito_temporal;

if (!mapaRaw || mapaRaw === '{}' || mapaRaw === '') {
  return [{
    json: {
      valido: false,
      mensaje: "⚠️ Tu sesión expiró. Escribe /start para reiniciar."
    }
  }];
}

let mapa;
try {
  mapa = JSON.parse(mapaRaw);
} catch(e) {
  return [{
    json: {
      valido: false,
      mensaje: "⚠️ Error interno. Escribe /start para reiniciar."
    }
  }];
}

const producto = mapa[numeroEscrito];

if (!producto) {
  const opciones = Object.keys(mapa).filter(k => !isNaN(k)).join(', ');
  return [{
    json: {
      valido: false,
      mensaje: `❌ Número inválido. Opciones: ${opciones}\n\n✏️ *Escribe el número del producto:*`
    }
  }];
}

// Recuperar items existentes si los hay
// El mapa puede tener keys numéricos (productos) o tener estructura con items
const itemsExistentes = mapa.items || [];

return [{
  json: {
    valido: true,
    producto_id: producto.id,
    producto_nombre: producto.nombre,
    producto_precio: producto.precio,
    mapa_raw: mapaRaw,
    mensaje: `✅ Seleccionaste: *${producto.nombre}*\n💰 Precio: $${producto.precio}\n\n¿Cuántas unidades deseas?`,
    nuevo_carrito_temporal: JSON.stringify({
      producto_seleccionado: {
        id: producto.id,
        nombre: producto.nombre,
        precio: producto.precio
      },
      mapa: mapa,
      items: itemsExistentes  // ← preserva el historial
    })
  }
}];

const productos = $input.all();

if (productos.length === 0 || !productos[0].json.id_producto) {
  return [{
    json: {
      hay_productos: false,
      mensaje: "⚠️ No hay productos disponibles en esta categoría."
    }
  }];
}

let textoMenu = `📋 *Productos disponibles*\n\n`;

productos.forEach((p, index) => {
  textoMenu += `*${index + 1}.* *${p.json.nombre}*\n`;
  textoMenu += `💰 Precio: $${p.json.precio}\n`;
  if (p.json.descripcion) {
    textoMenu += `📝 _${p.json.descripcion}_\n`;
  }
  textoMenu += `\n`;
});

textoMenu += `✏️ *Escribe el número del producto que deseas agregar a tu carrito:*`;

const mapaProductos = {};
productos.forEach((p, index) => {
  mapaProductos[String(index + 1)] = {
    id: p.json.id_producto,
    nombre: p.json.nombre,
    precio: Number(p.json.precio)
  };
});

return [{
  json: {
    hay_productos: true,
    mensaje: textoMenu,
    mapa_productos: JSON.stringify(mapaProductos)
  }
}];

// Tomar las actualizaciones de stock calculadas
const actualizaciones = $('Confirmar Stock + Generar Pedido').item.json.actualizaciones_stock;

// Devolver un item por cada producto a actualizar
return actualizaciones.map(a => ({
  json: {
    id_producto: a.id_producto,
    stock_nuevo: a.stock_nuevo,
    row_number: a.row_number
  }
}));

const construirOutput = $('Construir lista De Productos').item.json;

// Si no hay productos, pasar el mensaje de error directo
if (!construirOutput.hay_productos || !construirOutput.mapa_productos) {
  return [{
    json: {
      carrito_fusionado: '{}',
      mensaje: construirOutput.mensaje || '⚠️ No hay productos disponibles.'
    }
  }];
}

const mapaNuevo = JSON.parse(construirOutput.mapa_productos);

const sessionData = $('Leer estado Usuario').item.json;
let itemsExistentes = [];

try {
  const carritoActual = JSON.parse(sessionData.carrito_temporal || '{}');
  itemsExistentes = carritoActual.items || [];
} catch(e) {
  itemsExistentes = [];
}

const carritoFusionado = {
  ...mapaNuevo,
  items: itemsExistentes
};

return [{
  json: {
    carrito_fusionado: JSON.stringify(carritoFusionado),
    mensaje: construirOutput.mensaje
  }
}];

// Cantidad que escribió/tocó el usuario
const cantidadRaw = String($('Ajuste Variables').item.json.texto_usuario).trim();
const cantidad = Number(cantidadRaw);

// Validar que sea un número positivo
if (isNaN(cantidad) || cantidad <= 0 || !Number.isInteger(cantidad)) {
  return [{
    json: {
      valido: false,
      mensaje: "❌ Por favor escribe una cantidad válida (número entero mayor a 0)."
    }
  }];
}

// Leer SESSION para obtener el producto seleccionado
const sessionData = $input.first().json;
let carritoData;

try {
  carritoData = JSON.parse(sessionData.carrito_temporal);
} catch(e) {
  return [{
    json: {
      valido: false,
      mensaje: "⚠️ Error interno. Escribe /start para reiniciar."
    }
  }];
}

const producto = carritoData.producto_seleccionado;
const itemsExistentes = carritoData.items || [];

// Agregar el nuevo item
const nuevoItem = {
  id: producto.id,
  nombre: producto.nombre,
  precio: producto.precio,
  cantidad: cantidad,
  subtotal: producto.precio * cantidad
};

const itemsActualizados = [...itemsExistentes, nuevoItem];

// Calcular total
const total = itemsActualizados.reduce((sum, item) => sum + item.subtotal, 0);

// Construir resumen del carrito
let resumen = `🛒 *Tu carrito:*\n\n`;
itemsActualizados.forEach((item, i) => {
  resumen += `${i + 1}. ${item.nombre} x${item.cantidad} = $${item.subtotal}\n`;
});
resumen += `\n💰 *Total: $${total}*\n\n`;
resumen += `¿Qué deseas hacer?`;

return [{
  json: {
    valido: true,
    items: itemsActualizados,
    total: total,
    resumen: resumen,
    nuevo_carrito_temporal: JSON.stringify({
      items: itemsActualizados,
      total: total
    })
  }
}];
